void processCommand(int cmd) {
    switch (cmd) {
        default:  // Compliant - default first
            handleUnknownCommand();
            break;
        case 1:
            handleCommand1();
            break;
        case 2:
            handleCommand2();
            break;
        case 3:
            handleCommand3();
            break;
    }
}

